50: /**
51:  * A CDS (portfolio) index product. 
52:  * <p>
53:  * A CDS index is a portofolio of single name credit default swaps. 
54:  * The protection buyer periodically pays fixed coupons to the protection seller until the expiry, 
55:  * and in return, the protection buyer receives the bond of a defaulted constituent legal entity for par.  
56:  */
57: @BeanDefinition
58: public final class CdsIndex
59:     implements Product, Resolvable<ResolvedCdsIndex>, ImmutableBean, Serializable {
60: 
61:   /**
62:    * Whether the CDS index is buy or sell.
63:    * <p>
64:    * A value of 'Buy' implies buying protection, where the fixed coupon is paid
65:    * and the protection is received  in the event of default.
66:    * A value of 'Sell' implies selling protection, where the fixed coupon is received
67:    * and the protection is paid in the event of default.
68:    */
69:   @PropertyDefinition(validate = "notNull")
70:   private final BuySell buySell;
71:   /**
72:    * The CDS index identifier.
73:    * <p>
74:    * This identifier is used to refer this CDS index product.
75:    */
76:   @PropertyDefinition(validate = "notNull")
77:   private final StandardId cdsIndexId;
78:   /**
79:    * The legal entity identifiers.
80:    * <p>
81:    * These identifiers refer to the reference legal entities of the CDS index.
82:    */
83:   @PropertyDefinition(validate = "notNull")
84:   private final ImmutableList<StandardId> legalEntityIds;
85:   /**
86:    * The currency of the CDS index.
87:    * <p>
88:    * The amounts of the notional are expressed in terms of this currency.
89:    */
90:   @PropertyDefinition(validate = "notNull")
91:   private final Currency currency;
92:   /**
93:    * The notional amount, must be non-negative.
94:    * <p>
95:    * The fixed notional amount applicable during the lifetime of the CDS.
96:    * The currency of the notional is specified by {@code currency}.
97:    */
98:   @PropertyDefinition(validate = "ArgChecker.notNegativeOrZero")
99:   private final double notional;
100:   /**
101:    * The payment schedule.
102:    * <p>
103:    * This is used to define the payment periods.
104:    */
105:   @PropertyDefinition(validate = "notNull")
106:   private final PeriodicSchedule paymentSchedule;
107:   /**
108:    * The fixed coupon rate.
109:    * <p>
110:    * This must be represented in decimal form.
111:    */
112:   @PropertyDefinition(validate = "ArgChecker.notNegative")
113:   private final double fixedRate;
114:   /**
115:    * The day count convention.
116:    * <p>
117:    * This is used to convert dates to a numerical value.
118:    * <p>
119:    * When building, this will default to 'Act/360'.
120:    */
121:   @PropertyDefinition(validate = "notNull")
122:   private final DayCount dayCount;
123:   /**
124:    * The payment on default.
125:    * <p>
126:    * Whether the accrued premium is paid in the event of a default.
127:    * <p>
128:    * When building, this will default to 'AccruedPremium'.
129:    */
130:   @PropertyDefinition(validate = "notNull")
131:   private final PaymentOnDefault paymentOnDefault;
132:   /**
133:    * The protection start of the day.
134:    * <p>
135:    * When the protection starts on the start date.
136:    * <p>
137:    * When building, this will default to 'Beginning'.
138:    */
139:   @PropertyDefinition(validate = "notNull")
140:   private final ProtectionStartOfDay protectionStart;
141:   /**
142:    * The number of days between valuation date and step-in date.
143:    * <p>
144:    * The step-in date is also called protection effective date.
145:    * It is usually 1 calendar day for standardized CDS index contracts.
146:    * <p>
147:    * When building, this will default to 1 calendar day.
148:    */
149:   @PropertyDefinition(validate = "notNull")
150:   private final DaysAdjustment stepinDateOffset;
151:   /**
152:    * The number of days between valuation date and settlement date.
153:    * <p>
154:    * It is usually 3 business days for standardized CDS index contracts.
155:    * <p>
156:    * When building, this will default to 3 business days in the calendar of the payment schedule.
157:    */
158:   @PropertyDefinition(validate = "notNull")
159:   private final DaysAdjustment settlementDateOffset;
160: 
161:   //-------------------------------------------------------------------------
162:   /**
163:    * Creates an instance of a standardized CDS index.
164:    * 
165:    * @param buySell  buy or sell
166:    * @param cdsIndexId  the CDS index ID
167:    * @param legalEntityIds  the legal entity IDs
168:    * @param currency  the currency
169:    * @param notional  the notional
170:    * @param startDate  the start date
171:    * @param endDate  the end date
172:    * @param calendar  the calendar
173:    * @param paymentFrequency  the payment frequency
174:    * @param fixedRate  the fixed coupon rate
175:    * @return the instance
176:    */
177:   public static CdsIndex of(
178:       BuySell buySell,
179:       StandardId cdsIndexId,
180:       List<StandardId> legalEntityIds,
181:       Currency currency,
182:       double notional,
183:       LocalDate startDate,
184:       LocalDate endDate,
185:       Frequency paymentFrequency,
186:       HolidayCalendarId calendar,
187:       double fixedRate) {
188: 
189:     PeriodicSchedule accrualSchedule = PeriodicSchedule.builder()
190:         .businessDayAdjustment(BusinessDayAdjustment.of(BusinessDayConventions.FOLLOWING, calendar))
191:         .startDate(startDate)
192:         .endDate(endDate)
193:         .startDateBusinessDayAdjustment(BusinessDayAdjustment.NONE)
194:         .endDateBusinessDayAdjustment(BusinessDayAdjustment.NONE)
195:         .frequency(paymentFrequency)
196:         .rollConvention(RollConventions.NONE)
197:         .stubConvention(StubConvention.SMART_INITIAL)
198:         .build();
199:     return new CdsIndex(
200:         buySell,
201:         cdsIndexId,
202:         legalEntityIds,
203:         currency,
204:         notional,
205:         accrualSchedule,
206:         fixedRate,
207:         DayCounts.ACT_360,
208:         PaymentOnDefault.ACCRUED_PREMIUM,
209:         ProtectionStartOfDay.BEGINNING,
210:         DaysAdjustment.ofCalendarDays(1),
211:         DaysAdjustment.ofBusinessDays(3, calendar));
212:   }
213: 
214:   @ImmutableDefaults
215:   private static void applyDefaults(Builder builder) {
216:     builder.dayCount = DayCounts.ACT_360;
217:     builder.paymentOnDefault = PaymentOnDefault.ACCRUED_PREMIUM;
218:     builder.protectionStart = ProtectionStartOfDay.BEGINNING;
219:     builder.stepinDateOffset = DaysAdjustment.ofCalendarDays(1);
220:   }
