236:   //-------------------------------------------------------------------------
237:   @Override
238:   public ResolvedCdsIndex resolve(ReferenceData refData) {
239:     Schedule adjustedSchedule = paymentSchedule.createSchedule(refData);
240:     ImmutableList.Builder<CreditCouponPaymentPeriod> accrualPeriods = ImmutableList.builder();
241:     int nPeriods = adjustedSchedule.size();
242:     for (int i = 0; i < nPeriods - 1; i++) {
243:       SchedulePeriod period = adjustedSchedule.getPeriod(i);
244:       accrualPeriods.add(CreditCouponPaymentPeriod.builder()
245:           .startDate(period.getStartDate())
246:           .endDate(period.getEndDate())
247:           .unadjustedStartDate(period.getUnadjustedStartDate())
248:           .unadjustedEndDate(period.getUnadjustedEndDate())
249:           .effectiveStartDate(protectionStart.isBeginning() ? period.getStartDate().minusDays(1) : period.getStartDate())
250:           .effectiveEndDate(protectionStart.isBeginning() ? period.getEndDate().minusDays(1) : period.getEndDate())
251:           .paymentDate(period.getEndDate())
252:           .notional(notional)
253:           .currency(currency)
254:           .fixedRate(fixedRate)
255:           .yearFraction(period.yearFraction(dayCount, adjustedSchedule))
256:           .build());
257:     }
258:     // last period - accrual end is modified
259:     SchedulePeriod lastPeriod = adjustedSchedule.getPeriod(nPeriods - 1);
260:     LocalDate accEndDate = protectionStart.isBeginning() ? lastPeriod.getEndDate().plusDays(1) : lastPeriod.getEndDate();
261:     SchedulePeriod modifiedPeriod = lastPeriod.toBuilder().endDate(accEndDate).build();
262:     accrualPeriods.add(CreditCouponPaymentPeriod.builder()
263:         .startDate(modifiedPeriod.getStartDate())
264:         .endDate(modifiedPeriod.getEndDate())
265:         .unadjustedStartDate(modifiedPeriod.getUnadjustedStartDate())
266:         .unadjustedEndDate(modifiedPeriod.getUnadjustedEndDate())
267:         .effectiveStartDate(protectionStart.isBeginning() ? lastPeriod.getStartDate().minusDays(1) : lastPeriod.getStartDate())
268:         .effectiveEndDate(lastPeriod.getEndDate())
269:         .paymentDate(paymentSchedule.getBusinessDayAdjustment().adjust(lastPeriod.getEndDate(), refData))
270:         .notional(notional)
271:         .currency(currency)
272:         .fixedRate(fixedRate)
273:         .yearFraction(modifiedPeriod.yearFraction(dayCount, adjustedSchedule))
274:         .build());
275:     ImmutableList<CreditCouponPaymentPeriod> paymentPeriods = accrualPeriods.build();
276: 
277:     return ResolvedCdsIndex.builder()
278:         .buySell(buySell)
279:         .cdsIndexId(cdsIndexId)
280:         .legalEntityIds(legalEntityIds)
281:         .protectionStart(protectionStart)
282:         .paymentOnDefault(paymentOnDefault)
283:         .paymentPeriods(paymentPeriods)
284:         .protectionEndDate(lastPeriod.getEndDate())
285:         .settlementDateOffset(settlementDateOffset)
286:         .stepinDateOffset(stepinDateOffset)
287:         .dayCount(dayCount)
288:         .build();
289:   }
