38: /**
39:  * A CDS (portfolio) index, resolved for pricing.
40:  * <p>
41:  * This is the resolved form of {@link CdsIndex} and is an input to the pricers.
42:  * Applications will typically create a {@code ResolvedCdsIndex} from a {@code CdsIndex}
43:  * using {@link CdsIndex#resolve(ReferenceData)}.
44:  */
45: @BeanDefinition
46: public final class ResolvedCdsIndex
47:     implements ResolvedProduct, ImmutableBean, Serializable {
48: 
49:   /**
50:    * Whether the CDS index is buy or sell.
51:    * <p>
52:    * A value of 'Buy' implies buying protection, where the fixed coupon is paid
53:    * and the protection is received  in the event of default.
54:    * A value of 'Sell' implies selling protection, where the fixed coupon is received
55:    * and the protection is paid in the event of default.
56:    */
57:   @PropertyDefinition(validate = "notNull")
58:   private final BuySell buySell;
59:   /**
60:    * The CDS index identifier.
61:    * <p>
62:    * This identifier is used to refer this CDS index product.
63:    */
64:   @PropertyDefinition(validate = "notNull")
65:   private final StandardId cdsIndexId;
66:   /**
67:    * The legal entity identifiers.
68:    * <p>
69:    * These identifiers refer to the reference legal entities of the CDS index.
70:    */
71:   @PropertyDefinition(validate = "notNull")
72:   private final ImmutableList<StandardId> legalEntityIds;
73:   /**
74:    * The periodic payments based on the fixed rate.
75:    * <p>
76:    * Each payment period represents part of the life-time of the leg.
77:    * In most cases, the periods do not overlap. However, since each payment period
78:    * is essentially independent the data model allows overlapping periods.
79:    */
80:   @PropertyDefinition(validate = "notEmpty")
81:   private final ImmutableList<CreditCouponPaymentPeriod> paymentPeriods;
82:   /**
83:    * The protection end date.
84:    * <p>
85:    * This may be different from the accrual end date of the last payment period in {@code periodicPayments}.
86:    */
87:   @PropertyDefinition(validate = "notNull")
88:   private final LocalDate protectionEndDate;
89:   /**
90:    * The day count convention.
91:    * <p>
92:    * This is used to convert dates to a numerical value.
93:    */
94:   @PropertyDefinition(validate = "notNull")
95:   private final DayCount dayCount;
96:   /**
97:    * The payment on default.
98:    * <p>
99:    * Whether the accrued premium is paid in the event of a default.
100:    */
101:   @PropertyDefinition(validate = "notNull")
102:   private final PaymentOnDefault paymentOnDefault;
103:   /**
104:    * The protection start of the day.
105:    * <p>
106:    * When the protection starts on the start date.
107:    */
108:   @PropertyDefinition(validate = "notNull")
109:   private final ProtectionStartOfDay protectionStart;
110:   /**
111:    * The number of days between valuation date and step-in date.
112:    * <p>
113:    * The step-in date is also called protection effective date. 
114:    * It is usually 1 calendar day for standardized CDS index contracts. 
115:    */
116:   @PropertyDefinition(validate = "notNull")
117:   private final DaysAdjustment stepinDateOffset;
118:   /**
119:    * The number of days between valuation date and settlement date.
120:    * <p>
121:    * It is usually 3 business days for standardized CDS index contracts.
122:    */
123:   @PropertyDefinition(validate = "notNull")
124:   private final DaysAdjustment settlementDateOffset;
125: 
126:   //-------------------------------------------------------------------------
127:   /**
128:    * Obtains the accrual start date.
129:    * <p>
130:    * In general this is different from the protection start date. 
131:    * Use {@code stepinDateOffset} to compute the protection start date.
132:    * 
133:    * @return the accrual start date
134:    */
135:   public LocalDate getAccrualStartDate() {
136:     return paymentPeriods.get(0).getStartDate();
137:   }
138: 
139:   /**
140:    * Obtains the accrual end date.
141:    * 
142:    * @return the accrual end date
143:    */
144:   public LocalDate getAccrualEndDate() {
145:     return paymentPeriods.get(paymentPeriods.size() - 1).getEndDate();
146:   }
