          .endDate(period.getEndDate())
          .unadjustedStartDate(period.getUnadjustedStartDate())
          .unadjustedEndDate(period.getUnadjustedEndDate())
          .effectiveStartDate(period.getEffectiveStartDate())
          .effectiveEndDate(period.getEffectiveEndDate())
          .paymentDate(period.getPaymentDate())
          .notional(period.getNotional() * trancheWeight)
          .currency(period.getCurrency())
          .fixedRate(period.getFixedRate())
          .yearFraction(period.getYearFraction())
          .build());
    }

    return ResolvedCdsTranche.builder()
        .buySell(buySell)
        .underlyingIndex(resolvedIndex)
        .attachmentPoint(attachmentPoint)
        .detachmentPoint(detachmentPoint)
        .protectionStart(protectionStart)
        .paymentOnDefault(paymentOnDefault)
        .paymentPeriods(accrualPeriods.build())
        .protectionEndDate(resolvedIndex.getProtectionEndDate())
