/**
 * A CDS tranche product representing a slice of a CDS index portfolio.
 * <p>
 * A CDS tranche is a slice of credit risk from a CDS index portfolio, defined by attachment
 * and detachment points that determine the subordination level. The tranche buyer is only exposed
 * to losses between the attachment point and detachment point as a fraction of the index notional.
 */
@BeanDefinition
public final class CdsTranche
    implements Product, Resolvable<ResolvedCdsTranche>, ImmutableBean, Serializable {

  /**
   * Whether the CDS tranche is buy or sell.
   * <p>
   * A value of 'Buy' implies buying protection, where the fixed coupon is paid
