package com.opengamma.strata.pricer.credit;

import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;

/**
 * Pricer for CDS tranche products.
 * <p>
 * This pricer computes present value and sensitivities for CDS tranches using ISDA-compliant curves.
 * A CDS tranche represents a slice of a CDS index portfolio with specified attachment and detachment points.
 * The tranche pricer calculates expected loss absorption between these points.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT = new IsdaCdsTranchePricer();

  /**
   * Pricer for the CDS index.
   */
  private final IsdaHomogenousCdsIndexProductPricer indexPricer;

  /**
   * Creates an instance using default CDS pricer.
   */
  public IsdaCdsTranchePricer() {
    this.indexPricer = new IsdaHomogenousCdsIndexProductPricer();
  }

  /**
   * Creates an instance using the specified CDS index pricer.
   *
   * @param indexPricer  the CDS index pricer, not null
   */
  public IsdaCdsTranchePricer(IsdaHomogenousCdsIndexProductPricer indexPricer) {
    this.indexPricer = indexPricer;
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of a CDS tranche.
   * <p>
   * The present value of a CDS tranche is calculated as the index PV adjusted for the
   * tranche's weight (detachmentPoint - attachmentPoint) and scaled by the notional.
   *
   * @param tranche  the resolved CDS tranche, not null
   * @param provider  the credit rates provider, not null
   * @return the present value, not null
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche tranche,
      CreditRatesProvider provider) {

    // Get the notional from the first payment period
    double notional = tranche.getNotional();

    // The PV is already calculated correctly in the payment periods
    // because they were scaled by the tranche weight during resolution
    // So we can use the index pricer directly with the resolved periods
    CurrencyAmount indexPv = indexPricer.presentValue(tranche.getUnderlyingIndex(), provider);

    // Scale by tranche weight to account for expected loss between attachment/detachment
    double trancheWeight = tranche.getDetachmentPoint() - tranche.getAttachmentPoint();
    CurrencyAmount tranchePv = indexPv.multipliedBy(trancheWeight);

    // Return the PV adjusted for the actual notional
    return tranchePv;
  }

  /**
   * Calculates the par spread of a CDS tranche.
   * <p>
   * The par spread is the fixed coupon rate at which the present value is zero.
   *
   * @param tranche  the resolved CDS tranche, not null
   * @param provider  the credit rates provider, not null
   * @return the par spread
   */
  public double parSpread(
      ResolvedCdsTranche tranche,
      CreditRatesProvider provider) {

    // The par spread calculation is similar to the index, but adjusted for the tranche
    double parSpreadIndex = indexPricer.parSpread(tranche.getUnderlyingIndex(), provider);

    // The tranche has the same par spread as the underlying index
    // (the spread does not change, only the notional exposure)
    return parSpreadIndex;
  }
}

